// Pillar distribution weights: 40% Education, 25% Inspiration, 20% Product, 15% Community
const PILLARS = [
  { label: 'Education', weight: 40 },
  { label: 'Inspiration', weight: 25 },
  { label: 'Product', weight: 20 },
  { label: 'Community', weight: 15 },
];

function pickPillar() {
  const rand = Math.random() * 100;
  let cumulative = 0;
  for (const pillar of PILLARS) {
    cumulative += pillar.weight;
    if (rand < cumulative) return pillar.label;
  }
  return PILLARS[0].label;
}

// Get topics from Google Sheets response
const sheetData = $input.first().json;
const topics = Array.isArray(sheetData) ? sheetData : (sheetData.values || []);

// Filter pending topics (not yet published)
const pending = topics.filter(row => {
  const status = Array.isArray(row) ? row[2] : row.status;
  return !status || status === '' || status === 'pending';
});

if (pending.length === 0) {
  throw new Error('No pending topics in backlog. Please add topics to the Google Sheet.');
}

// Pick the first pending topic
const topicRow = pending[0];
const topicTitle = Array.isArray(topicRow) ? topicRow[0] : topicRow.topic;
const topicNotes = Array.isArray(topicRow) ? (topicRow[1] || '') : (topicRow.notes || '');
const pillar = pickPillar();

return [
  {
    json: {
      topic: topicTitle,
      notes: topicNotes,
      pillar: pillar,
      timestamp: new Date().toISOString(),
      rowIndex: topics.indexOf(topicRow),
    }
  }
];

